// --- CONFIGURAÇÃO DE PERFORMANCE ---
const LIMITE_TREINO = 30; // Só treina a cada 10 sorteios recebidos
const ENTRADAS = 15;      // Lotofácil: 15 números
const MAX_VAL = 25;       // Lotofácil: vai de 1 a 25
// ------------------------------------

let sorteioAtual = msg.payload.numeros;
let rede = global.get('loto_network');
let previsaoAnterior = global.get('loto_previsao_ia');
let contador = global.get('loto_count_batch') || 0;

// Inicializa a rede se não existir
if (!rede) {
    rede = new Architect.Perceptron(ENTRADAS, 30, ENTRADAS);
    global.set('loto_network', rede);
    node.status({ fill: 'blue', shape: 'dot', text: 'Rede Loto Inicializada' });
}

// 1. Calcular acertos (Baseado na previsão feita no sorteio anterior)
let acertos = 0;
if (previsaoAnterior) {
    acertos = sorteioAtual.filter(n => previsaoAnterior.includes(n)).length;
}

// 2. Lógica de Treinamento Leve (Batch Processing)
let historico = global.get('loto_history') || [];
contador++;

if (contador >= LIMITE_TREINO && historico.length > 0) {
    // Treina com o último par (anterior -> atual)
    let entradaTreino = historico[historico.length - 1].map(n => n / MAX_VAL);
    let saidaDesejada = sorteioAtual.map(n => n / MAX_VAL);

    // Executa apenas 10 iterações para não travar o Event Loop
    for (let i = 0; i < 10; i++) {
        rede.activate(entradaTreino);
        rede.propagate(0.3, saidaDesejada);
    }
    contador = 0; // Reinicia o contador após o treino
    node.warn("IA Loto: Ciclo de treinamento concluído.");
}

// 3. Gerar Previsão para o PRÓXIMO sorteio (Cálculo rápido de ativação)
let tentativaBruta = rede.activate(sorteioAtual.map(n => n / MAX_VAL));
let previsaoParaProximo = [];
let seguranca = 0;

while (previsaoParaProximo.length < ENTRADAS && seguranca < 100) {
    let n = Math.round(tentativaBruta[seguranca % ENTRADAS] * MAX_VAL);
    if (n < 1) n = 1;
    if (n > MAX_VAL) n = MAX_VAL;

    // Se o número já existe, incrementa até achar um vago
    while (previsaoParaProximo.includes(n)) {
        n = (n % MAX_VAL) + 1;
    }
    previsaoParaProximo.push(n);
    seguranca++;
}

