historico.push(sorteioAtual);
if (historico.length > 50) historico.shift(); // Mantém histórico curto para poupar RAM

global.set('loto_history', historico);
global.set('loto_previsao_ia', previsaoParaProximo);
global.set('loto_count_batch', contador);

// Prepara o payload de saída
msg.payload = {
    semente: msg.payload.semente,
    hash: msg.payload.hash,
    numeros: sorteioAtual,
    ia_tentativa: previsaoAnterior ? previsaoAnterior.sort((a, b) => a - b).join(', ') : 'Treinando...',
    ia_acertos: acertos
};

node.status({
    fill: contador === 0 ? 'green' : 'yellow',
    shape: 'dot',
    text: `Acertos: ${acertos}/15 | Lote: ${contador}/${LIMITE_TREINO}`
});

return msg;

