if (!msg.payload.timestamp) {
    const now = new Date();
    const p = n => String(n).padStart(2, '0');
    msg.payload.timestamp = `${p(now.getDate())}/${p(now.getMonth() + 1)}/${now.getFullYear()} ${p(now.getHours())}:${p(now.getMinutes())}:${p(now.getSeconds())}`;
}

msg.url = GAS_URL + '?token=' + GAS_TOKEN;
msg.method = 'POST';
msg.payload = JSON.stringify(msg.payload);
msg.headers = { 'Content-Type': 'application/json' };
return msg;
